code_sb &lt;- nimble::nimbleCode({
  alpha ~ dgamma(1, 1)

  for (k in 1:(K - 1)) {
    v[k] ~ dbeta(1, alpha)
  }
  v[K] &lt;- 1

  w[1] &lt;- v[1]
  for (k in 2:K) {
    w[k] &lt;- v[k] * prod(1 - v[1:(k - 1)])
  }

  for (k in 1:K) {
    mu[k] ~ dnorm(0, sd = 5)
    sigma[k] ~ dunif(0.1, 5)
  }

  for (i in 1:N) {
    y[i] ~ dNormMix(w = w[1:K], mean = mu[1:K], sd = sigma[1:K])
  }
})

